/**
 * Typed view over the committed backend-benchmark results.
 *
 * The JSON is generated by `web/scripts/collect-benchmarks.ts` (run via
 * `npm run collect:benchmarks`) from criterion's output — never hand-edited.
 * This module just types it and adds display metadata, mirroring the
 * typed-data-module idiom of `solvers.ts` / `problems.ts`.
 */
import rawData from './backend-benchmarks.json';

/** Solvers that run on all four backends (the backend axis). */
export type Solver = 'gd' | 'nm' | 'lbfgs';
/** Linear-algebra backends. */
export type Backend = 'vec' | 'nalgebra' | 'ndarray' | 'faer';

export interface BenchResult {
    solver: Solver;
    problem: string;
    n: number;
    backend: Backend;
    /** Mean estimate, nanoseconds. */
    ns: number;
    /** 95% confidence interval on the mean, nanoseconds. */
    lowNs: number;
    highNs: number;
}

export interface BackendBenchmarks {
    /** ISO date (YYYY-MM-DD) the results were measured. */
    generatedAt: string;
    env: { os: string; arch: string; cpu: string };
    /** Fixed iteration budget each solve ran for. */
    iterations: number;
    results: BenchResult[];
}

export const BACKEND_BENCHMARKS = rawData as BackendBenchmarks;

export const SOLVER_ORDER: Solver[] = ['gd', 'nm', 'lbfgs'];
export const BACKEND_ORDER: Backend[] = ['vec', 'nalgebra', 'ndarray', 'faer'];

export const SOLVER_LABELS: Record<Solver, string> = {
    gd: 'Gradient Descent',
    nm: 'Nelder–Mead',
    lbfgs: 'L-BFGS',
};

export const BACKEND_LABELS: Record<Backend, string> = {
    vec: 'Vec<f64>',
    nalgebra: 'nalgebra',
    ndarray: 'ndarray',
    faer: 'faer',
};

/** Line/legend colors per backend — mid-tone hues legible on both light and
 * dark backgrounds (indigo / sky / amber / rose). Shared by the chart lines
 * and the legend so they never drift. */
export const BACKEND_COLORS: Record<Backend, string> = {
    vec: '#6366f1',
    nalgebra: '#0ea5e9',
    ndarray: '#f59e0b',
    faer: '#f43f5e',
};

/** Format a nanosecond duration with an appropriate unit. */
export function formatDuration(ns: number): string {
    if (ns < 1_000) return `${ns.toFixed(0)} ns`;
    if (ns < 1_000_000) return `${(ns / 1_000).toFixed(1)} µs`;
    return `${(ns / 1_000_000).toFixed(2)} ms`;
}
